import test from 'node:test';
import assert from 'node:assert/strict';
import { PolicyStore } from '../src/policy-store.mjs';
import { AuditLog } from '../src/audit-log.mjs';
import { Authorizer } from '../src/authorizer.mjs';

test('a route added during identity lookup is not visible to the earlier request', async () => {
  let releaseIdentity;
  const identityReady = new Promise((resolve) => {
    releaseIdentity = resolve;
  });
  const store = new PolicyStore({ '/stable': ['tester'] });
  const audit = new AuditLog(store);
  const authorizer = new Authorizer({
    store,
    audit,
    resolveIdentity: () => identityReady,
  });

  const pending = authorizer.authorize({ token: 'slow', route: '/preview' });
  await Promise.resolve();
  store.replace({ '/stable': ['tester'], '/preview': ['tester'] });
  releaseIdentity({ subject: 'user-12', role: 'tester' });

  assert.deepEqual(await pending, {
    subject: 'user-12',
    route: '/preview',
    allowed: false,
    policyVersion: 1,
  });
  assert.deepEqual(audit.entries(), [{
    subject: 'user-12',
    route: '/preview',
    allowed: false,
    policyVersion: 1,
  }]);
});
